def classify_strict(title, desc):
    text = (title + " " + desc).lower()

    # Points
    st_score = 0
    bus_score = 0

    # Business indicators
    if re.search(r'\b(stock|market|dow|nasdaq|revenue|profit|earnings|share|shares|investor|economy|bank|trade|merger|acquisition|deal|corp|inc|company|buyout|ceo|sales)\b', text):
        bus_score += 2
    if 'business' in text:
        bus_score += 1

    # Sci/Tech indicators
    # Strong S/T
    if re.search(r'\b(science|technology|computer|software|browser|internet|web|space|nasa|orbit|biology|physics|research|lab|robot|gadget|wireless|broadband|satellite|telescope|astronomy|genetic|stem cell|genome|virus|security|hacker|firewall|spam|spyware)\b', text):
        st_score += 2

    # Specific Tech Companies/Products
    if re.search(r'\b(microsoft|google|apple|intel|ibm|linux|windows|gameboy|nintendo|xbox|playstation|sony|sega|wii|ipod|itunes|firefox|explorer|netscape|oracle|cisco|dell|hp|hewlett|packard|palm)\b', text):
        st_score += 2

    # Weak S/T (context dependent)
    if re.search(r'\b(tech|mobile|phone|device|innovation|online|digital|electronic|network|chip|mars|moon|universe)\b', text):
        st_score += 1

    # Ambiguous
    if 'game' in text and not re.search(r'\b(video|console|boy|cube|station)\b', text):
        # likely sports if "win", "score", "team" present
        if re.search(r'\b(team|coach|player|sport|football|soccer|baseball|basketball)\b', text):
            pass # It's sports
        else:
            st_score += 0.5 # Slight tech lean? Or just noise.

    # Decision
    # Business trumps S/T if strictly business news about tech (e.g. merger)
    # But "New iPod released" -> S/T.
    # "Oracle buys PeopleSoft" -> Business.

    if st_score > 0:
        if bus_score >= st_score + 1:
            return "Business"
        if bus_score > 0 and st_score == 1:
            return "Business"
        return "Sci/Tech"

    return "Other"

st_titles = []
for a in articles:
    if classify_strict(a['title'], a['description']) == "Sci/Tech":
        st_titles.append(a['title'])

print("__RESULT__:")
print(json.dumps({"count": len(st_titles), "titles": st_titles}))
